 `include "lpc_defines.v"

-module lpc_host (clk_i, ctrl_addr_i, ctrl_data_i, ctrl_nrst_i, ctrl_lframe_i,
-                 ctrl_rd_status_i, ctrl_wr_status_i, ctrl_memory_cycle_i,
