+  // FSM - finite state machine : LPC Host
+  always @(posedge clk_i) begin
+    lad_reg <= LPC_LAD;
+    if (fsm_host_state == `LPC_ST_FORCE_RESET) begin
+      if (~ctrl_nrst_i) begin
+        LPC_LRESET = 0;
+        LPC_LFRAME = 1;
+        lad_en = 0;
+        lad_out = 4'b0000;
+        ctrl_ready_o = 0;
+      end else begin
