+        end else if (ctrl_lframe_i & ctrl_wr_status_i) begin
+          LPC_LFRAME = 1;
+          lad_out = 4'b0110;
+          fsm_host_state = `LPC_ST_CYCTYPE_MEMORY_WR;
+        end
+      end
+    end
         else if ((fsm_host_state == `LPC_ST_CYCTYPE_RD) || (fsm_host_state == `LPC_ST_CYCTYPE_MEMORY_RD)) begin
