-        end
-        else if (fsm_host_state == `LPC_ST_DATA_RD_CLK1) begin
-            ctrl_data_o[7:4] = LPC_LAD;
-            fsm_host_state = `LPC_ST_DATA_RD_CLK2;
-        end
-        else if (fsm_host_state == `LPC_ST_DATA_RD_CLK2) begin
-            fsm_host_state = `LPC_ST_FINAL_TAR_CLK1;
